"use strict";

document.addEventListener('DOMContentLoaded', () => {
    console.log("JavaScript chargé avec succès."); // Pour débogage

    /* ============================
       Fonctionnalité : Menu Burger
    ============================ */
    (() => {
        const burger = document.querySelector('.burger');
        const nav = document.querySelector('.nav-links');
        const navLinks = document.querySelectorAll('.nav-links li');

        if (!burger || !nav) {
            console.error('Éléments du menu burger non trouvés. Vérifiez les classes CSS.');
            return;
        }

        const toggleNav = () => {
            console.log("Burger menu cliqué."); // Log pour vérifier l'appel
            nav.classList.toggle('nav-active');
            burger.classList.toggle('toggle');

            // Mettre à jour l'attribut ARIA pour indiquer l'état du menu
            const isExpanded = burger.classList.contains('toggle');
            burger.setAttribute('aria-expanded', isExpanded);

            // Gérer les animations via les classes CSS
            navLinks.forEach((link, index) => {
                link.style.animation = nav.classList.contains('nav-active')
                    ? `navLinkFade 0.5s ease forwards ${index / 7 + 0.3}s`
                    : '';
            });
        };

        // Écouteurs d'événements
        burger.addEventListener('click', toggleNav);
        navLinks.forEach(link => {
            link.addEventListener('click', () => {
                if (nav.classList.contains('nav-active')) {
                    console.log("Lien de navigation cliqué. Fermeture du menu."); // Log
                    toggleNav();
                }
            });
        });
    })();

    /* ============================
       Fonctionnalité : Gestion des Modales
    ============================ */
    (() => {
        const openModalButtons = document.querySelectorAll('.open-modal');
        const closeModalButtons = document.querySelectorAll('.modal .close-modal');

        // Fonction pour ouvrir la modale
        openModalButtons.forEach(button => {
            button.addEventListener('click', (e) => {
                e.preventDefault();
                const targetModalId = button.getAttribute('data-modal');
                console.log(`Tentative d'ouverture de la modal: ${targetModalId}`); // Log
                const modal = document.getElementById(targetModalId);

                if (!modal) {
                    console.error(`Modale avec l'ID "${targetModalId}" non trouvée.`);
                    return;
                }

                // Si c'est la modale des projets, injecter les données dynamiquement
                if (modal.id === 'project-modal') {
                    const title = button.getAttribute('data-title');
                    const imgSrc = button.getAttribute('data-img');
                    const description = button.getAttribute('data-description');
                    const link = button.getAttribute('data-link');

                    // Vérifier que les éléments existent avant de les modifier
                    const modalTitle = modal.querySelector('#modal-title');
                    const modalImg = modal.querySelector('#modal-img');
                    const modalDescription = modal.querySelector('#modal-description');
                    const modalLink = modal.querySelector('#modal-link');

                    if (modalTitle) modalTitle.textContent = title || 'Titre du Projet';
                    if (modalImg) {
                        modalImg.src = imgSrc !== "#" ? imgSrc : 'img/default-project.png'; // Remplacer par une image par défaut si nécessaire
                        modalImg.alt = `Image du projet ${title || 'Projet'}`;
                    }
                    if (modalDescription) modalDescription.textContent = description || 'Description du projet...';
                    if (modalLink) {
                        modalLink.href = link || '#';
                        modalLink.style.display = link ? 'inline-block' : 'none'; // Masquer le lien si pas de lien fourni
                    }
                }

                // Afficher la modale
                modal.classList.add('active');
                modal.setAttribute('aria-hidden', 'false');
                document.body.style.overflow = 'hidden';
            });
        });

        // Fonction pour fermer les modales
        closeModalButtons.forEach(button => {
            button.addEventListener('click', () => {
                const modal = button.closest('.modal');
                if (modal) {
                    console.log(`Fermeture de la modale: ${modal.id}`); // Log
                    closeModal(modal);
                }
            });
        });

        // Fermer la modale en cliquant en dehors du contenu
        window.addEventListener('click', (e) => {
            if (e.target.classList.contains('modal')) {
                console.log(`Fermeture de la modale en cliquant en dehors: ${e.target.id}`); // Log
                closeModal(e.target);
            }
        });

        // Fermer la modale en appuyant sur la touche Échap
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                console.log(`Fermeture de toutes les modales avec Échap.`); // Log
                document.querySelectorAll('.modal.active').forEach(modal => {
                    closeModal(modal);
                });
            }
        });

        /**
         * Ferme une modale donnée.
         * @param {HTMLElement} modal - La modale à fermer.
         */
        function closeModal(modal) {
            modal.classList.remove('active');
            modal.setAttribute('aria-hidden', 'true');
            document.body.style.overflow = '';
        }
    })();

    /* ============================
       Fonctionnalité : Bouton "Retour en haut"
    ============================ */
    (() => {
        const scrollTopButton = document.getElementById('scroll-top');

        if (!scrollTopButton) {
            console.error('Bouton "Retour en haut" non trouvé. Vérifiez l\'ID du bouton.');
            return;
        }

        /**
         * Affiche ou cache le bouton "Retour en haut" en fonction du défilement.
         */
        const toggleScrollTopButton = () => {
            const isVisible = window.scrollY > 300;
            console.log(`Affichage du bouton "Retour en haut": ${isVisible}`); // Log
            scrollTopButton.classList.toggle('visible', isVisible);
        };

        // Écouteur d'événement pour le défilement
        window.addEventListener('scroll', toggleScrollTopButton);
        toggleScrollTopButton(); // Initialiser l'état au chargement

        // Scroll vers le haut lorsque le bouton est cliqué
        scrollTopButton.addEventListener('click', () => {
            console.log(`Bouton "Retour en haut" cliqué.`); // Log
            window.scrollTo({
                top: 0,
                behavior: 'smooth'
            });
        });
    })();
});

// Initialize EmailJS
(function(){
    emailjs.init("oxjRO8a9Xk0pSU4AG"); // Replace with your actual EmailJS user ID
})();

// Form Submit Handler
document.getElementById('contactForm').addEventListener('submit', function(event) {
    event.preventDefault(); // Prevent default form submission

    // Get form values
    const userName = document.getElementById('name').value;
    const userEmail = document.getElementById('email').value;
    const userMessage = document.getElementById('message').value;

    // Log form values
    console.log("Form submitted with values:", { userName, userEmail, userMessage });

    // Parameters for receiving email (to you)
    const receiveParams = {
        name: userName,
        email: userEmail,
        message: userMessage
    };

    // Afficher la section de chargement
    const loadingDiv = document.querySelector('.loading');
    loadingDiv.style.display = 'block'; // Afficher la section de chargement

    // Send the client's message to your email
    emailjs.send('service_nttg82g', 'template_and0lor', receiveParams)
        .then(function(response) {
            console.log('Client message sent successfully:', response.status, response.text);

            // Send the automatic response to the client
            return emailjs.send('service_nttg82g', 'template_q4an1f8', {
                name: userName,
                message: userMessage,
                email: userEmail
            });
        })
        .then(function(response) {
            console.log('Auto response sent successfully:', response.status, response.text);
            
            // Redirection vers la page de confirmation
            window.location.href = 'confirmation.html'; // Redirection vers confirmation.html
        })
        .catch(function(error) {
            console.error('Failed to send message:', error);
            alert('Failed to send your message. Please try again later.');

            // Masquer la section de chargement en cas d'erreur
            loadingDiv.style.display = 'none';
        });
});